const PD=[
{t:"best of 2024",tf:"meilleur de 2024",p:[0,1],
 n1:{en:"This moment right here.\nI almost missed it.\nBut the light held on\njust long enough. \u2661",fr:"Cet instant pr\u00e9cis.\nJ'ai failli le manquer.\nMais la lumi\u00e8re a tenu\njuste assez. \u2661"},
 n2:{en:"She looked at me\nlike I was her\nwhole entire universe.\nAnd maybe I am.",fr:"Elle m'a regard\u00e9\ncomme si j'\u00e9tais\nson univers entier.\nEt peut-\u00eatre que je le suis."},
 big:{en:"remember",fr:"souviens-toi"},sub:{en:"The most beautiful feeling\nin the world is when you\nrealize you were made\nfor each other.",fr:"Le plus beau sentiment\nau monde c'est quand\non r\u00e9alise qu'on \u00e9tait\nfait l'un pour l'autre."}},
{t:"golden moments",tf:"moments dor\u00e9s",p:[2,3],
 n1:{en:"Three generations.\nOne heartbeat.\nOne infinite love.\nForever grateful. \u2728",fr:"Trois g\u00e9n\u00e9rations.\nUn seul battement.\nUn amour infini.\nReconnaissance \u00e9ternelle. \u2728"},
 n2:{en:"She doesn't just glow.\nShe IS the light.\nAnd everyone around her\nfeels it too.",fr:"Elle ne brille pas\nseulement.\nElle EST la lumi\u00e8re.\nEt tout le monde\nautour le ressent."},
 big:{en:"family",fr:"famille"},sub:{en:"Sometimes I can't believe\nhow lucky I am\nto capture these souls.",fr:"Parfois je n'arrive pas\n\u00e0 croire la chance\nque j'ai de capturer\nces \u00e2mes."}},
{t:"love & light",tf:"amour & lumi\u00e8re",p:[4,5],
 n1:{en:"Elegance isn't\nwhat you wear.\nIt's how you carry\nyour beautiful soul. \u2605",fr:"\u00c9l\u00e9gance, ce n'est pas\nce qu'on porte.\nC'est comment on porte\nsa belle \u00e2me. \u2605"},
 n2:{en:"Two hearts.\nOne rhythm.\nNo words needed.\nJust this.",fr:"Deux c\u0153urs.\nUn seul rythme.\nPas de mots.\nJuste \u00e7a."},
 big:{en:"tender",fr:"tendresse"},sub:{en:"I live for the moments\nthat make time\nstand completely still.",fr:"Je vis pour les moments\nqui font que le temps\ns'arr\u00eate compl\u00e8tement."}},
{t:"the in-between",tf:"l'entre-deux",p:[6,7],
 n1:{en:"Some people make\nordinary Tuesday\nafternoons feel like\npure magic. \ud83c\udf3f",fr:"Certaines personnes\nrendent un mardi\napr\u00e8s-midi ordinaire\ncompl\u00e8tement magique. \ud83c\udf3f"},
 n2:{en:"Walking into\nthe unknown.\nHand in hand.\nHeart to heart.\nStep by step.",fr:"Marcher vers\nl'inconnu.\nMain dans la main.\nC\u0153ur \u00e0 c\u0153ur.\nPas \u00e0 pas."},
 big:{en:"breathe",fr:"respire"},sub:{en:"Not every beautiful thing\nneeds to be loud.\nSome are whispers.",fr:"Les belles choses\nn'ont pas besoin\nd'\u00eatre bruyantes.\nCertaines sont\ndes murmures."}},
{t:"new chapters",tf:"nouveaux chapitres",p:[8,9],
 n1:{en:"Two hearts beating\nas one. Three, soon.\nThe most beautiful\ncountdown ever. \ud83e\udd0d",fr:"Deux c\u0153urs\nqui battent \u00e0 l'unisson.\nBient\u00f4t trois.\nLe plus beau\ncompte \u00e0 rebours. \ud83e\udd0d"},
 n2:{en:"Wrapped in wool\nand winter light.\nShe is fire\nin human form.",fr:"Envelopp\u00e9e de laine\net de lumi\u00e8re d'hiver.\nElle est feu\nsous forme humaine."},
 big:{en:"forever",fr:"\u00e9ternit\u00e9"},sub:{en:"Every person I photograph\nteaches me something\nabout love I didn't\nknow before.",fr:"Chaque personne\nque je photographie\nm'apprend quelque chose\nsur l'amour."}},
{t:"quiet strength",tf:"force tranquille",p:[10,11],
 n1:{en:"She sat there\nlike a poem\nwaiting to be\nread out loud.\nAnd I listened. \ud83c\udf42",fr:"Elle \u00e9tait assise\ncomme un po\u00e8me\nqui attendait\nd'\u00eatre lu.\nEt j'ai \u00e9cout\u00e9. \ud83c\udf42"},
 n2:{en:"Silk catches light\nthe way skin\ncatches memories.\nSoftly. Gently.\nForever.",fr:"La soie attrape\nla lumi\u00e8re\ncomme la peau\nattrape les souvenirs.\nDoucement. Pour toujours."},
 big:{en:"dream",fr:"r\u00eave"},sub:{en:"Photography is my way\nof saying 'I see you'\nwithout making a sound.",fr:"La photo c'est ma fa\u00e7on\nde dire 'je te vois'\nsans faire de bruit."}},
{t:"love stories",tf:"histoires d'amour",p:[12,13],
 n1:{en:"Lavender dreams\nand whispered promises\nunder a summer sky.\nThis is what\nforever looks like. \ud83d\udc9c",fr:"R\u00eaves de lavande\net promesses murmur\u00e9es\nsous un ciel d'\u00e9t\u00e9.\nVoil\u00e0 \u00e0 quoi\nressemble l'\u00e9ternit\u00e9. \ud83d\udc9c"},
 n2:{en:"50 years later\nand they still look\nat each other like\nit's the very\nfirst time. \ud83e\udd79",fr:"50 ans plus tard\net ils se regardent\nencore comme\nla toute\npremi\u00e8re fois. \ud83e\udd79"},
 big:{en:"always",fr:"toujours"},sub:{en:"Love doesn't age.\nIt just gets\nmore beautiful\nwith time.",fr:"L'amour ne vieillit pas.\nIl devient juste\nplus beau\navec le temps."}},
{t:"little wonders",tf:"petites merveilles",p:[14,15],
 n1:{en:"Rain doesn't stop\nadventures.\nIt makes them\na thousand times\nmore magical. \u2602\ufe0f",fr:"La pluie n'arr\u00eate pas\nles aventures.\nElle les rend\nmille fois\nplus magiques. \u2602\ufe0f"},
 n2:{en:"Sometimes the\nmost beautiful things\nare said without\na single word.\nJust a look.\nJust a touch.",fr:"Parfois les\nplus belles choses\nse disent sans\nun seul mot.\nJuste un regard.\nJuste un geste."},
 big:{en:"magic",fr:"magie"},sub:{en:"Children remind us\nthat joy is not\nsomething you find.\nIt's something you are.",fr:"Les enfants nous rappellent\nque la joie n'est pas\nquelque chose qu'on trouve.\nC'est ce qu'on est."}},
{t:"the journey",tf:"le voyage",p:[16,17],
 n1:{en:"Citrus mornings\nand the beautiful art\nof slowing down.\nOf being present.\nOf just... being. \ud83c\udf3b",fr:"Matins citronn\u00e9s\net le bel art\nde ralentir.\nD'\u00eatre pr\u00e9sent.\nDe juste... \u00eatre. \ud83c\udf3b"},
 n2:{en:"Every golden morning\nis a love letter\nfrom the universe.\nI just happen to\nhave a camera.",fr:"Chaque matin dor\u00e9\nest une lettre d'amour\nde l'univers.\nMoi j'ai juste\nun appareil photo."},
 big:{en:"begin",fr:"d\u00e9but"},sub:{en:"Every ending\nis just a new beginning.\nThank you for being\npart of my story. \u2661",fr:"Chaque fin\nn'est qu'un nouveau d\u00e9but.\nMerci de faire partie\nde mon histoire. \u2661"}}
];

