<div className="hw" style={{left:"54%",top:"18%",fontSize:"clamp(.6rem,1.2vw,.78rem)",color:"rgba(255,255,255,.3)",maxWidth:"42%",fontFamily:"'Caveat',cursive"}}>{cp.sub[lang]}</div>

